code:
generic
  type Real is digits <>;
  type Index is range <>;
  type Vector is array (Index range <>) of Real;
package Sparse

record_types.code:
type CRS_matrix (rows_max_p1, nnz_max : Index) is record
  val       : Vector (1 .. nnz_max);
  col_ind   : Index_Array (1 .. nnz_max);
  row_ptr   : Index_Array (1 .. rows_max_p1);
  symmetric : Boolean;
  rows      : Index := rows_max_p1 - 1;
  nnz       : Index := nnz_max;
end record;
